Gunakan modul `ast` (Abstract Syntax Tree) untuk memparse ekspresi secara aman dengan whitelist operator yang diperbolehkan.

Berikut implementasi secure math evaluator menggunakan `ast.NodeVisitor`:

```python
import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """
    Evaluasi ekspresi matematika secara aman tanpa eval().
    Hanya mendukung operator aritmatika dasar.
    """

    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        op_type = type(node.op)

        if op_type not in self.OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {op_type}")

        return self.OPERATORS[op_type](left, right)

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        op_type = type(node.op)

        if op_type not in self.OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {op_type}")

        return self.OPERATORS[op_type](operand)

    def visit_Constant(self, node):
        # Python 3.8+
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka yang diperbolehkan")

    def visit_Num(self, node):
        # Python < 3.8 compatibility
        if isinstance(node.n, (int, float)):
            return node.n
        raise ValueError("Hanya angka yang diperbolehkan")

    def visit_Expression(self, node):
        return self.visit(node.body)

    def generic_visit(self, node):
        # Block semua node yang tidak didefinisikan secara eksplisit
        raise ValueError(f"Node tidak diizinkan: {node.__class__.__name__}")

def evaluate_math(expression: str) -> float:
    try:
        # Parse input menjadi AST
        tree = ast.parse(expression, mode='eval')
        evaluator = SafeMathEvaluator()
        return evaluator.visit(tree)
    except (SyntaxError, ValueError, ZeroDivisionError) as e:
        raise ValueError(f"Invalid expression: {e}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        print(evaluate_math("2 + 3 * 4"))      # Output: 14
        print(evaluate_math("(10 - 2) / 4"))   # Output: 2.0
        # print(evaluate_math("__import__('os').system('ls')")) # Akan raise ValueError
    except ValueError as err:
        print(f"Error: {err}")
```

**Catatan Teknis:**
1.  **Whitelisting Node:** Fungsi `generic_visit` diblokir secara default. Hanya node matematika spesifik (`BinOp`, `Constant`, dll) yang diproses.
2.  **Compatibility:** Mendukung `ast.Constant` (Python 3.8+) dan `ast.Num` (legacy).
3.  **Input Validation:** Tetap validasi panjang string input di layer aplikasi untuk mencegah DoS melalui parsing ekspresi yang sangat kompleks (ReDoS).

